/* ─── Global Reset & Base ──────────────────────────────────────────────────── */

*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html,
body {
  height: 100%;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
  font-size: 14px;
  color: #e0e0e0;
  background: #1a1a2e;
}

#app {
  height: 100%;
}

/* ─── Login Modal ─────────────────────────────────────────────────────────── */

.login-overlay {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.6);
  backdrop-filter: blur(6px);
  z-index: 1000;
}

.login-dialog {
  background: #16213e;
  border: 1px solid #0f3460;
  border-radius: 12px;
  padding: 32px;
  width: 380px;
  max-width: 90vw;
  text-align: center;
}

.login-dialog h2 {
  margin-bottom: 20px;
  color: #e94560;
  font-size: 1.5rem;
}

.login-form {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.login-form label {
  text-align: left;
  font-weight: 600;
  color: #a0a0c0;
}

.login-form input {
  padding: 10px 14px;
  border: 1px solid #0f3460;
  border-radius: 6px;
  background: #1a1a2e;
  color: #e0e0e0;
  font-size: 1rem;
  outline: none;
}

.login-form input:focus {
  border-color: #e94560;
}

.login-form button {
  padding: 10px;
  background: #e94560;
  color: white;
  border: none;
  border-radius: 6px;
  font-size: 1rem;
  font-weight: 600;
  cursor: pointer;
}

.login-form button:hover {
  background: #d63851;
}

.error-msg {
  color: #ff6b6b;
  margin-top: 10px;
  min-height: 1.2em;
}

/* ─── App Layout ──────────────────────────────────────────────────────────── */

.app-content {
  display: flex;
  flex-direction: column;
  height: 100%;
}

.app-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 16px;
  background: #16213e;
  border-bottom: 1px solid #0f3460;
  flex-shrink: 0;
}

.app-header h1 {
  font-size: 1.2rem;
  color: #e94560;
}

.header-right {
  display: flex;
  align-items: center;
  gap: 12px;
}

#user-display {
  color: #a0c4ff;
  font-weight: 600;
}

.header-right button {
  padding: 6px 14px;
  background: #533483;
  color: white;
  border: none;
  border-radius: 4px;
  cursor: pointer;
  font-size: 0.85rem;
}

.header-right button:hover {
  background: #6b44a0;
}

/* ─── Error Banner ────────────────────────────────────────────────────────── */

.error-banner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 16px;
  background: #5c1a1a;
  border-bottom: 1px solid #ff6b6b;
  color: #ffaaaa;
  flex-shrink: 0;
}

.error-banner button {
  background: none;
  border: none;
  color: #ffaaaa;
  font-size: 1.2rem;
  cursor: pointer;
  padding: 0 4px;
}

/* ─── Main Layout (sidebar + content) ─────────────────────────────────────── */

.app-layout {
  display: flex;
  flex: 1;
  min-height: 0;
  overflow: hidden;
}

/* ─── Sidebar ─────────────────────────────────────────────────────────────── */

.sidebar {
  width: 260px;
  min-width: 200px;
  background: #16213e;
  border-right: 1px solid #0f3460;
  display: flex;
  flex-direction: column;
  overflow-y: auto;
  flex-shrink: 0;
}

.panel {
  padding: 12px;
  border-bottom: 1px solid #0f3460;
}

.panel h2 {
  font-size: 0.9rem;
  text-transform: uppercase;
  color: #a0a0c0;
  margin-bottom: 8px;
  letter-spacing: 0.5px;
}

.panel-controls {
  display: flex;
  flex-direction: column;
  gap: 6px;
  margin-bottom: 8px;
}

.panel-controls input {
  padding: 6px 10px;
  border: 1px solid #0f3460;
  border-radius: 4px;
  background: #1a1a2e;
  color: #e0e0e0;
  font-size: 0.85rem;
  outline: none;
}

.panel-controls input:focus {
  border-color: #e94560;
}

.panel-buttons {
  display: flex;
  gap: 4px;
  flex-wrap: wrap;
}

.panel-buttons button {
  padding: 4px 8px;
  background: #0f3460;
  color: #e0e0e0;
  border: 1px solid #1a4080;
  border-radius: 4px;
  cursor: pointer;
  font-size: 0.8rem;
  display: flex;
  align-items: center;
  gap: 2px;
}

.panel-buttons button:hover {
  background: #1a4080;
}

.current-label {
  font-size: 0.8rem;
  color: #a0c4ff;
  padding: 4px 0;
}

/* ─── Item Lists (workspace/channel items) ────────────────────────────────── */

.item-list {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.item-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 6px 8px;
  border-radius: 4px;
  cursor: pointer;
  transition: background 0.15s;
}

.item-row:hover {
  background: #1a3a5c;
}

.item-name {
  flex: 1;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.item-delete {
  background: none;
  border: none;
  color: #ff6b6b;
  cursor: pointer;
  padding: 2px;
  display: flex;
  align-items: center;
  opacity: 0.5;
}

.item-delete:hover {
  opacity: 1;
}

/* ─── Main Content Area ───────────────────────────────────────────────────── */

.main-content {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-width: 0;
  overflow: hidden;
}

.channel-header {
  padding: 12px 16px;
  border-bottom: 1px solid #0f3460;
  background: #16213e;
  flex-shrink: 0;
}

.channel-header h2 {
  font-size: 1.1rem;
  color: #a0c4ff;
}

/* ─── Posts ────────────────────────────────────────────────────────────────── */

.post-container {
  flex: 1;
  overflow-y: auto;
  padding: 12px 16px;
}

.post-item {
  background: #16213e;
  border: 1px solid #0f3460;
  border-radius: 8px;
  padding: 10px 14px;
  margin-bottom: 8px;
  transition: background 0.15s;
}

.post-item:hover {
  background: #1a2a4e;
}

.post-header {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 4px;
}

.post-author {
  color: #a0c4ff;
  font-size: 0.9rem;
}

.post-time {
  color: #666;
  font-size: 0.75rem;
}

.post-body {
  margin-bottom: 8px;
  line-height: 1.5;
  word-wrap: break-word;
}

.post-body a {
  color: #64b5f6;
  text-decoration: underline;
}

.post-body strong {
  color: #fff;
}

.post-actions {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.reactions {
  display: flex;
  gap: 4px;
  flex-wrap: wrap;
}

.reaction-btn {
  display: flex;
  align-items: center;
  gap: 3px;
  padding: 3px 8px;
  background: #1a1a2e;
  border: 1px solid #0f3460;
  border-radius: 14px;
  color: #a0a0c0;
  cursor: pointer;
  font-size: 0.8rem;
}

.reaction-btn:hover {
  background: #0f3460;
}

.reaction-btn.active {
  background: #2a4a7e;
  border-color: #4a7abe;
  color: #e0e0e0;
}

.reaction-count {
  font-size: 0.75rem;
  min-width: 0.8em;
}

.reply-btn {
  padding: 3px 10px;
  background: none;
  border: 1px solid #0f3460;
  border-radius: 4px;
  color: #a0a0c0;
  cursor: pointer;
  font-size: 0.8rem;
}

.reply-btn:hover {
  background: #0f3460;
  color: #e0e0e0;
}

/* ─── Post Input ──────────────────────────────────────────────────────────── */

.post-input-area {
  padding: 12px 16px;
  background: #16213e;
  border-top: 1px solid #0f3460;
  flex-shrink: 0;
}

.reply-indicator {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 6px 10px;
  margin-bottom: 8px;
  background: #1a3a5c;
  border-radius: 4px;
  color: #a0c4ff;
  font-size: 0.85rem;
}

.reply-indicator button {
  background: none;
  border: none;
  color: #ff6b6b;
  font-size: 1.1rem;
  cursor: pointer;
  padding: 0 4px;
}

.input-toolbar {
  display: flex;
  gap: 4px;
  margin-bottom: 6px;
  flex-wrap: wrap;
}

.input-toolbar button {
  padding: 4px 8px;
  background: #1a1a2e;
  border: 1px solid #0f3460;
  border-radius: 4px;
  color: #a0a0c0;
  cursor: pointer;
  font-size: 0.85rem;
  display: flex;
  align-items: center;
}

.input-toolbar button:hover {
  background: #0f3460;
}

.toolbar-separator {
  width: 1px;
  background: #0f3460;
  margin: 0 4px;
}

.input-row {
  display: flex;
  gap: 8px;
}

.input-row textarea {
  flex: 1;
  padding: 8px 12px;
  border: 1px solid #0f3460;
  border-radius: 6px;
  background: #1a1a2e;
  color: #e0e0e0;
  font-size: 0.9rem;
  font-family: inherit;
  resize: vertical;
  min-height: 38px;
  outline: none;
}

.input-row textarea:focus {
  border-color: #e94560;
}

.input-row button {
  padding: 8px 18px;
  background: #e94560;
  color: white;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  font-weight: 600;
  font-size: 0.9rem;
  align-self: flex-end;
}

.input-row button:hover {
  background: #d63851;
}

import { App } from "./app";
import { slog } from "./slog";

/**
 * Entry point: initialize the application after the DOM is loaded.
 */
document.addEventListener("DOMContentLoaded", () => {
  slog.info("Using database", [
    "database",
    `${process.env.DATABASE_HOST}${process.env.DATABASE_PATH}`,
  ]);

  const root = document.getElementById("app");
  if (!root) {
    slog.error("Root element #app not found");
    return;
  }

  new App(root);
});

import * as api from "./api";
import type { PostEvent } from "./api";
import { isPostDoc } from "./schemas";
import type { DocumentResponse } from "./schemas";
import { renderMarkdown } from "./markdown";
import { slog } from "./slog";

// ─── Types ───────────────────────────────────────────────────────────────────

interface PostData {
  path: string;
  msg: string;
  parent: string;
  author: string;
  createdAt: number;
  reactions: Record<string, string[]>;
}

interface FlatPost {
  post: PostData;
  depth: number;
}

// ─── Reaction config ─────────────────────────────────────────────────────────

const REACTIONS: { name: string; icon: string; label: string }[] = [
  { name: ":smile:", icon: "mdi:emoticon-happy-outline", label: "smile" },
  { name: ":frown:", icon: "mdi:emoticon-sad-outline", label: "frown" },
  { name: ":like:", icon: "mdi:thumb-up-outline", label: "like" },
  { name: ":celebrate:", icon: "mdi:party-popper", label: "celebrate" },
];

// ─── App Class ───────────────────────────────────────────────────────────────

export class App {
  // State
  private token = "";
  private username = "";
  private currentWorkspace = "";
  private currentChannel = "";
  private posts = new Map<string, PostData>();
  private abortController: AbortController | null = null;
  private replyParentPath = "";
  private errorTimeout: ReturnType<typeof setTimeout> | null = null;

  // Root element
  private root: HTMLElement;

  constructor(root: HTMLElement) {
    this.root = root;
    this.buildUI();
    this.setupEventListeners();
    this.showLoginModal();
  }

  // ─── Build UI ──────────────────────────────────────────────────────────────

  private buildUI(): void {
    this.root.innerHTML = `
      <!-- Login Modal Overlay -->
      <div id="login-overlay" class="login-overlay">
        <div class="login-dialog" role="dialog" aria-modal="true" aria-label="Login">
          <h2>Login to M3ssag1n8</h2>
          <div class="login-form">
            <label for="username-input">Username</label>
            <input id="username-input" type="text" data-cy="username-input"
                   placeholder="Enter your username" aria-label="Username" />
            <button data-cy="login-btn" aria-label="Login">Login</button>
          </div>
          <div id="login-error" class="error-msg" role="alert"></div>
        </div>
      </div>

      <!-- Main App (hidden until login) -->
      <div id="app-content" class="app-content" style="display:none;">
        <!-- Header -->
        <header class="app-header">
          <h1>M3ssag1n8</h1>
          <div class="header-right">
            <span id="user-display" data-cy="user-display"></span>
            <button data-cy="logout-btn" aria-label="Logout">Logout</button>
          </div>
        </header>

        <!-- Error Banner -->
        <div id="error-banner" class="error-banner" role="alert" style="display:none;">
          <span id="error-text"></span>
          <button id="error-dismiss" aria-label="Dismiss error">&times;</button>
        </div>

        <!-- Main Layout -->
        <div class="app-layout">
          <!-- Sidebar -->
          <aside class="sidebar">
            <!-- Workspaces Section -->
            <section class="panel" aria-label="Workspaces">
              <h2>Workspaces</h2>
              <div class="panel-controls">
                <input type="text" data-cy="ws-name-input" placeholder="Workspace name"
                       aria-label="Workspace name" />
                <div class="panel-buttons">
                  <button data-cy="ws-open-btn" aria-label="Open workspace" title="Open">Open</button>
                  <button data-cy="ws-create-btn" aria-label="Create workspace" title="Create">Create</button>
                  <button data-cy="ws-delete-btn" aria-label="Delete workspace" title="Delete">Delete</button>
                  <button data-cy="ws-refresh-btn" aria-label="Refresh workspaces" title="Refresh">
                    <iconify-icon icon="mdi:refresh" aria-label="refresh"></iconify-icon>
                  </button>
                </div>
              </div>
              <div id="ws-list" class="item-list" data-cy="ws-list"></div>
              <div id="ws-current" class="current-label" style="display:none;">
                Open: <strong id="ws-current-name"></strong>
              </div>
            </section>

            <!-- Channels Section -->
            <section class="panel" aria-label="Channels" id="channel-section" style="display:none;">
              <h2>Channels</h2>
              <div class="panel-controls">
                <input type="text" data-cy="ch-name-input" placeholder="Channel name"
                       aria-label="Channel name" />
                <div class="panel-buttons">
                  <button data-cy="ch-open-btn" aria-label="Open channel" title="Open">Open</button>
                  <button data-cy="ch-create-btn" aria-label="Create channel" title="Create">Create</button>
                  <button data-cy="ch-delete-btn" aria-label="Delete channel" title="Delete">Delete</button>
                  <button data-cy="ch-refresh-btn" aria-label="Refresh channels" title="Refresh">
                    <iconify-icon icon="mdi:refresh" aria-label="refresh"></iconify-icon>
                  </button>
                </div>
              </div>
              <div id="ch-list" class="item-list" data-cy="ch-list"></div>
            </section>
          </aside>

          <!-- Main Content Area -->
          <main class="main-content" id="main-content">
            <div id="channel-header" class="channel-header" style="display:none;">
              <h2 id="channel-name"></h2>
            </div>
            <div id="post-container" class="post-container"></div>
            <div id="post-input-area" class="post-input-area" style="display:none;">
              <div id="reply-indicator" class="reply-indicator" style="display:none;">
                Replying to post...
                <button id="reply-close-btn" data-cy="reply-close-btn" aria-label="Cancel reply">&times;</button>
              </div>
              <div class="input-toolbar">
                <button data-cy="bold-btn" aria-label="Bold" title="Bold"><strong>B</strong></button>
                <button data-cy="italic-btn" aria-label="Italic" title="Italic"><em>I</em></button>
                <button data-cy="link-btn" aria-label="Link" title="Link">
                  <iconify-icon icon="mdi:link" aria-label="link"></iconify-icon>
                </button>
                <span class="toolbar-separator"></span>
                <button data-cy="emoji-smile" aria-label="smile" title=":smile:">
                  <iconify-icon icon="mdi:emoticon-happy-outline" aria-label="smile"></iconify-icon>
                </button>
                <button data-cy="emoji-frown" aria-label="frown" title=":frown:">
                  <iconify-icon icon="mdi:emoticon-sad-outline" aria-label="frown"></iconify-icon>
                </button>
                <button data-cy="emoji-like" aria-label="like" title=":like:">
                  <iconify-icon icon="mdi:thumb-up-outline" aria-label="like"></iconify-icon>
                </button>
                <button data-cy="emoji-celebrate" aria-label="celebrate" title=":celebrate:">
                  <iconify-icon icon="mdi:party-popper" aria-label="celebrate"></iconify-icon>
                </button>
              </div>
              <div class="input-row">
                <textarea data-cy="post-input" placeholder="Type a message..."
                          aria-label="Message input" rows="2"></textarea>
                <button data-cy="post-submit-btn" aria-label="Send message">Post</button>
              </div>
            </div>
          </main>
        </div>
      </div>
    `;
  }

  // ─── DOM Helpers ───────────────────────────────────────────────────────────

  private el<T extends HTMLElement>(selector: string): T {
    return this.root.querySelector(selector) as T;
  }

  // ─── Event Listeners ──────────────────────────────────────────────────────

  private setupEventListeners(): void {
    // Login
    this.el<HTMLButtonElement>('[data-cy="login-btn"]').addEventListener("click", () =>
      this.handleLogin(),
    );
    this.el<HTMLInputElement>('[data-cy="username-input"]').addEventListener(
      "keydown",
      (e) => {
        if (e.key === "Enter") this.handleLogin();
      },
    );

    // Logout
    this.el<HTMLButtonElement>('[data-cy="logout-btn"]').addEventListener("click", () =>
      this.handleLogout(),
    );

    // Error dismiss
    this.el<HTMLButtonElement>("#error-dismiss").addEventListener("click", () =>
      this.hideError(),
    );

    // Workspace controls
    this.el<HTMLButtonElement>('[data-cy="ws-open-btn"]').addEventListener("click", () =>
      this.handleOpenWorkspace(),
    );
    this.el<HTMLButtonElement>('[data-cy="ws-create-btn"]').addEventListener("click", () =>
      this.handleCreateWorkspace(),
    );
    this.el<HTMLButtonElement>('[data-cy="ws-delete-btn"]').addEventListener("click", () =>
      this.handleDeleteWorkspace(),
    );
    this.el<HTMLButtonElement>('[data-cy="ws-refresh-btn"]').addEventListener("click", () =>
      this.loadWorkspaces(),
    );

    // Channel controls
    this.el<HTMLButtonElement>('[data-cy="ch-open-btn"]').addEventListener("click", () =>
      this.handleOpenChannel(),
    );
    this.el<HTMLButtonElement>('[data-cy="ch-create-btn"]').addEventListener("click", () =>
      this.handleCreateChannel(),
    );
    this.el<HTMLButtonElement>('[data-cy="ch-delete-btn"]').addEventListener("click", () =>
      this.handleDeleteChannel(),
    );
    this.el<HTMLButtonElement>('[data-cy="ch-refresh-btn"]').addEventListener("click", () =>
      this.loadChannels(),
    );

    // Post input
    this.el<HTMLButtonElement>('[data-cy="post-submit-btn"]').addEventListener("click", () =>
      this.handleSubmitPost(),
    );
    this.el<HTMLTextAreaElement>('[data-cy="post-input"]').addEventListener(
      "keydown",
      (e) => {
        if (e.key === "Enter" && !e.shiftKey) {
          e.preventDefault();
          this.handleSubmitPost();
        }
      },
    );

    // Reply close
    this.el<HTMLButtonElement>("#reply-close-btn").addEventListener("click", () =>
      this.cancelReply(),
    );

    // Toolbar buttons
    this.el<HTMLButtonElement>('[data-cy="bold-btn"]').addEventListener("click", () =>
      this.insertFormat("**", "**"),
    );
    this.el<HTMLButtonElement>('[data-cy="italic-btn"]').addEventListener("click", () =>
      this.insertFormat("*", "*"),
    );
    this.el<HTMLButtonElement>('[data-cy="link-btn"]').addEventListener("click", () =>
      this.insertFormat("[", "](url)"),
    );
    this.el<HTMLButtonElement>('[data-cy="emoji-smile"]').addEventListener("click", () =>
      this.insertText(":smile:"),
    );
    this.el<HTMLButtonElement>('[data-cy="emoji-frown"]').addEventListener("click", () =>
      this.insertText(":frown:"),
    );
    this.el<HTMLButtonElement>('[data-cy="emoji-like"]').addEventListener("click", () =>
      this.insertText(":like:"),
    );
    this.el<HTMLButtonElement>('[data-cy="emoji-celebrate"]').addEventListener("click", () =>
      this.insertText(":celebrate:"),
    );

    // Workspace list click delegation
    this.el("#ws-list").addEventListener("click", (e) => {
      const target = e.target as HTMLElement;
      const item = target.closest("[data-ws-name]") as HTMLElement | null;
      if (!item) return;
      const name = item.getAttribute("data-ws-name") || "";
      if (target.closest(".item-delete")) {
        this.doDeleteWorkspace(name);
      } else {
        this.doOpenWorkspace(name);
      }
    });

    // Channel list click delegation
    this.el("#ch-list").addEventListener("click", (e) => {
      const target = e.target as HTMLElement;
      const item = target.closest("[data-ch-name]") as HTMLElement | null;
      if (!item) return;
      const name = item.getAttribute("data-ch-name") || "";
      if (target.closest(".item-delete")) {
        this.doDeleteChannel(name);
      } else {
        this.doOpenChannel(name);
      }
    });
  }

  // ─── Login / Logout ───────────────────────────────────────────────────────

  private showLoginModal(): void {
    this.el("#login-overlay").style.display = "flex";
    this.el("#app-content").style.display = "none";
  }

  private hideLoginModal(): void {
    this.el("#login-overlay").style.display = "none";
    this.el("#app-content").style.display = "flex";
  }

  private async handleLogin(): Promise<void> {
    const input = this.el<HTMLInputElement>('[data-cy="username-input"]');
    const username = input.value.trim();
    if (!username) return;

    try {
      const res = await api.login(username);
      this.token = res.token;
      this.username = username;
      this.el("#login-error").textContent = "";
      this.hideLoginModal();
      this.el("#user-display").textContent = username;
      this.loadWorkspaces();
    } catch (err) {
      this.el("#login-error").textContent =
        err instanceof Error ? err.message : "Login failed";
    }
  }

  private async handleLogout(): Promise<void> {
    try {
      await api.logout(this.token);
    } catch (err) {
      slog.warn("Logout error", ["error", String(err)]);
    }
    this.closeChannel();
    this.closeWorkspace();
    this.token = "";
    this.username = "";
    this.el("#user-display").textContent = "";
    this.el<HTMLInputElement>('[data-cy="username-input"]').value = "";
    this.hideError();
    this.showLoginModal();
  }

  // ─── Error Banner ─────────────────────────────────────────────────────────

  private showError(msg: string): void {
    if (this.errorTimeout) clearTimeout(this.errorTimeout);
    this.el("#error-text").textContent = msg;
    this.el("#error-banner").style.display = "flex";
  }

  private hideError(): void {
    if (this.errorTimeout) {
      clearTimeout(this.errorTimeout);
      this.errorTimeout = null;
    }
    this.el("#error-banner").style.display = "none";
    this.el("#error-text").textContent = "";
  }

  // ─── Workspaces ───────────────────────────────────────────────────────────

  private async loadWorkspaces(): Promise<void> {
    try {
      const docs = await api.getWorkspaces(this.token);
      const list = this.el("#ws-list");
      list.innerHTML = "";
      for (const doc of docs) {
        const name = this.nameFromPath(doc.path);
        const item = document.createElement("div");
        item.className = "item-row";
        item.setAttribute("data-ws-name", name);
        item.setAttribute("data-cy", "ws-item");
        item.innerHTML = `
          <span class="item-name">${this.escapeHtml(name)}</span>
          <button class="item-delete" aria-label="Delete ${this.escapeHtml(name)}" title="Delete">
            <iconify-icon icon="mdi:close" aria-label="delete"></iconify-icon>
          </button>
        `;
        list.appendChild(item);
      }
    } catch (err) {
      slog.warn("Failed to load workspaces", ["error", String(err)]);
    }
  }

  private handleOpenWorkspace(): void {
    const input = this.el<HTMLInputElement>('[data-cy="ws-name-input"]');
    const name = input.value.trim();
    if (!name) return;
    input.value = "";
    this.doOpenWorkspace(name);
  }

  private async doOpenWorkspace(name: string): Promise<void> {
    this.hideError();
    try {
      await api.getWorkspace(this.token, name);
      this.closeChannel();
      this.currentWorkspace = name;
      this.el("#ws-current").style.display = "block";
      this.el("#ws-current-name").textContent = name;
      this.el("#channel-section").style.display = "block";
      this.loadChannels();
    } catch (err) {
      this.showError(err instanceof Error ? err.message : "Error opening workspace");
    }
  }

  private handleCreateWorkspace(): void {
    const input = this.el<HTMLInputElement>('[data-cy="ws-name-input"]');
    const name = input.value.trim();
    if (!name) return;
    input.value = "";
    this.doCreateWorkspace(name);
  }

  private async doCreateWorkspace(name: string): Promise<void> {
    this.hideError();
    try {
      await api.createWorkspace(this.token, name);
      await this.loadWorkspaces();
      // Auto-open created workspace
      this.closeChannel();
      this.currentWorkspace = name;
      this.el("#ws-current").style.display = "block";
      this.el("#ws-current-name").textContent = name;
      this.el("#channel-section").style.display = "block";
      this.loadChannels();
    } catch (err) {
      this.showError(err instanceof Error ? err.message : "Error creating workspace");
    }
  }

  private handleDeleteWorkspace(): void {
    const input = this.el<HTMLInputElement>('[data-cy="ws-name-input"]');
    const name = input.value.trim();
    if (!name) return;
    input.value = "";
    this.doDeleteWorkspace(name);
  }

  private async doDeleteWorkspace(name: string): Promise<void> {
    this.hideError();
    try {
      await api.deleteWorkspace(this.token, name);
      // Close workspace if it was open
      this.closeWorkspace();
      await this.loadWorkspaces();
    } catch (err) {
      this.showError(err instanceof Error ? err.message : "Error deleting workspace");
    }
  }

  private closeWorkspace(): void {
    this.closeChannel();
    this.currentWorkspace = "";
    this.el("#ws-current").style.display = "none";
    this.el("#ws-current-name").textContent = "";
    this.el("#channel-section").style.display = "none";
    this.el("#ch-list").innerHTML = "";
  }

  // ─── Channels ─────────────────────────────────────────────────────────────

  private async loadChannels(): Promise<void> {
    if (!this.currentWorkspace) return;
    try {
      const docs = await api.getChannels(this.token, this.currentWorkspace);
      const list = this.el("#ch-list");
      list.innerHTML = "";
      for (const doc of docs) {
        const name = this.nameFromPath(doc.path);
        const item = document.createElement("div");
        item.className = "item-row";
        item.setAttribute("data-ch-name", name);
        item.setAttribute("data-cy", "ch-item");
        item.innerHTML = `
          <span class="item-name">${this.escapeHtml(name)}</span>
          <button class="item-delete" aria-label="Delete ${this.escapeHtml(name)}" title="Delete">
            <iconify-icon icon="mdi:close" aria-label="delete"></iconify-icon>
          </button>
        `;
        list.appendChild(item);
      }
    } catch (err) {
      slog.warn("Failed to load channels", ["error", String(err)]);
    }
  }

  private handleOpenChannel(): void {
    const input = this.el<HTMLInputElement>('[data-cy="ch-name-input"]');
    const name = input.value.trim();
    if (!name) return;
    input.value = "";
    this.doOpenChannel(name);
  }

  private async doOpenChannel(name: string): Promise<void> {
    if (!this.currentWorkspace) return;
    this.hideError();
    try {
      await api.getChannel(this.token, this.currentWorkspace, name);
      this.closeChannel();
      this.currentChannel = name;
      this.el("#channel-header").style.display = "block";
      this.el("#channel-name").textContent = name;
      this.el("#post-input-area").style.display = "block";
      this.subscribeToPosts();
    } catch (err) {
      this.showError(err instanceof Error ? err.message : "Error opening channel");
    }
  }

  private handleCreateChannel(): void {
    const input = this.el<HTMLInputElement>('[data-cy="ch-name-input"]');
    const name = input.value.trim();
    if (!name) return;
    input.value = "";
    this.doCreateChannel(name);
  }

  private async doCreateChannel(name: string): Promise<void> {
    if (!this.currentWorkspace) return;
    this.hideError();
    try {
      await api.createChannel(this.token, this.currentWorkspace, name);
      await this.loadChannels();
    } catch (err) {
      this.showError(err instanceof Error ? err.message : "Error creating channel");
    }
  }

  private handleDeleteChannel(): void {
    const input = this.el<HTMLInputElement>('[data-cy="ch-name-input"]');
    const name = input.value.trim();
    if (!name) return;
    input.value = "";
    this.doDeleteChannel(name);
  }

  private async doDeleteChannel(name: string): Promise<void> {
    if (!this.currentWorkspace) return;
    this.hideError();
    try {
      await api.deleteChannel(this.token, this.currentWorkspace, name);
      if (this.currentChannel === name) {
        this.closeChannel();
      }
      await this.loadChannels();
    } catch (err) {
      this.showError(err instanceof Error ? err.message : "Error deleting channel");
    }
  }

  private closeChannel(): void {
    this.abortController?.abort();
    this.abortController = null;
    this.currentChannel = "";
    this.posts.clear();
    this.replyParentPath = "";
    this.el("#channel-header").style.display = "none";
    this.el("#channel-name").textContent = "";
    this.el("#post-container").innerHTML = "";
    this.el("#post-input-area").style.display = "none";
    this.el("#reply-indicator").style.display = "none";
    // Move input back to bottom
    const inputArea = this.el("#post-input-area");
    this.el("#main-content").appendChild(inputArea);
  }

  // ─── Posts ────────────────────────────────────────────────────────────────

  private async subscribeToPosts(): Promise<void> {
    if (!this.currentWorkspace || !this.currentChannel) return;

    this.abortController?.abort();
    this.abortController = new AbortController();
    this.posts.clear();
    this.el("#post-container").innerHTML = "";

    // First GET existing posts
    try {
      const docs = await api.getPosts(
        this.token,
        this.currentWorkspace,
        this.currentChannel,
      );
      for (const doc of docs) {
        this.processPostEvent({
          type: "update",
          path: doc.path,
          doc: doc.doc as Record<string, unknown>,
          meta: doc.meta as PostEvent["meta"],
        });
      }
    } catch (err) {
      slog.warn("Failed to load posts", ["error", String(err)]);
    }

    // Then subscribe for live updates
    api.subscribeToChannel(
      this.token,
      this.currentWorkspace,
      this.currentChannel,
      (event) => this.processPostEvent(event),
      this.abortController.signal,
    );
  }

  private processPostEvent(event: PostEvent): void {
    if (event.type === "update" && event.doc && event.meta) {
      if (!isPostDoc(event.doc)) return;
      const postData: PostData = {
        path: event.path,
        msg: String(event.doc.msg || ""),
        parent: String(event.doc.parent || ""),
        author: event.meta.createdBy,
        createdAt: event.meta.createdAt,
        reactions: (event.doc.reactions || {}) as Record<string, string[]>,
      };
      this.posts.set(event.path, postData);
      this.renderPosts();
    } else if (event.type === "delete") {
      this.posts.delete(event.path);
      this.renderPosts();
    }
  }

  private renderPosts(): void {
    const container = this.el("#post-container");
    const flatList = this.buildFlatPostList();

    // Remember where the input area is
    const inputArea = this.el("#post-input-area");
    const inputParentPath = this.replyParentPath;

    container.innerHTML = "";

    for (const { post, depth } of flatList) {
      const postEl = this.createPostElement(post, depth);
      container.appendChild(postEl);

      // If we're replying to this post, insert input after it
      if (inputParentPath && this.pathInDb(post.path) === inputParentPath) {
        container.appendChild(inputArea);
      }
    }

    // If not replying (or reply parent not found), input stays at bottom
    if (!inputParentPath) {
      this.el("#main-content").appendChild(inputArea);
    }
  }

  private buildFlatPostList(): FlatPost[] {
    const allPosts = Array.from(this.posts.values());
    // Build parent -> children map
    const childMap = new Map<string, PostData[]>();
    const topLevel: PostData[] = [];

    for (const p of allPosts) {
      const parentKey = p.parent || "";
      if (!parentKey) {
        topLevel.push(p);
      } else {
        // Find parent by matching pathInDb
        let matched = false;
        for (const candidate of allPosts) {
          if (this.pathInDb(candidate.path) === parentKey) {
            const children = childMap.get(candidate.path) || [];
            children.push(p);
            childMap.set(candidate.path, children);
            matched = true;
            break;
          }
        }
        if (!matched) {
          // Parent not found, treat as top-level
          topLevel.push(p);
        }
      }
    }

    // Sort by creation time
    topLevel.sort((a, b) => a.createdAt - b.createdAt);

    // DFS to flatten
    const result: FlatPost[] = [];
    const dfs = (posts: PostData[], depth: number) => {
      for (const p of posts) {
        result.push({ post: p, depth });
        const children = childMap.get(p.path) || [];
        children.sort((a, b) => a.createdAt - b.createdAt);
        dfs(children, depth + 1);
      }
    };
    dfs(topLevel, 0);
    return result;
  }

  private createPostElement(post: PostData, depth: number): HTMLElement {
    const el = document.createElement("div");
    el.className = "post-item";
    el.setAttribute("data-cy", "post-item");
    el.setAttribute("data-post-path", post.path);
    el.style.marginLeft = `${depth * 30}px`;

    const time = new Date(post.createdAt).toLocaleString();

    // Build reactions HTML
    let reactionsHtml = "";
    for (const r of REACTIONS) {
      const users = post.reactions[r.name] || [];
      const count = users.length;
      const active = users.includes(this.username) ? " active" : "";
      reactionsHtml += `
        <button class="reaction-btn${active}" data-reaction="${r.name}"
                aria-label="${r.label} reaction" title="${r.name}">
          <iconify-icon icon="${r.icon}" aria-label="${r.label}" width="16" height="16"></iconify-icon>
          <span class="reaction-count">${count > 0 ? count : ""}</span>
        </button>
      `;
    }

    el.innerHTML = `
      <div class="post-header">
        <strong class="post-author">${this.escapeHtml(post.author)}</strong>
        <span class="post-time">${this.escapeHtml(time)}</span>
      </div>
      <div class="post-body">${renderMarkdown(post.msg)}</div>
      <div class="post-actions">
        <div class="reactions">${reactionsHtml}</div>
        <button class="reply-btn" data-cy="reply-btn" aria-label="Reply">Reply</button>
      </div>
    `;

    // Reaction click handlers
    el.querySelectorAll(".reaction-btn").forEach((btn) => {
      btn.addEventListener("click", (e) => {
        e.stopPropagation();
        const reaction = (btn as HTMLElement).getAttribute("data-reaction") || "";
        this.handleReaction(post, reaction);
      });
    });

    // Reply click handler
    el.querySelector(".reply-btn")?.addEventListener("click", () => {
      this.startReply(post);
    });

    return el;
  }

  // ─── Reactions ────────────────────────────────────────────────────────────

  private async handleReaction(post: PostData, reactionName: string): Promise<void> {
    const currentUsers = post.reactions[reactionName] || [];
    let newUsers: string[];
    if (currentUsers.includes(this.username)) {
      newUsers = currentUsers.filter((u) => u !== this.username);
    } else {
      newUsers = [...currentUsers, this.username];
    }

    const newReactions = { ...post.reactions, [reactionName]: newUsers };

    try {
      await api.patchReactions(this.token, post.path, newReactions);
      // Optimistically update local state
      post.reactions = newReactions;
      this.renderPosts();
    } catch (err) {
      slog.warn("Failed to update reaction", ["error", String(err)]);
    }
  }

  // ─── Reply ────────────────────────────────────────────────────────────────

  private startReply(post: PostData): void {
    this.replyParentPath = this.pathInDb(post.path);
    this.el("#reply-indicator").style.display = "flex";
    this.renderPosts();
    this.el<HTMLTextAreaElement>('[data-cy="post-input"]').focus();
  }

  private cancelReply(): void {
    this.replyParentPath = "";
    this.el("#reply-indicator").style.display = "none";
    // Move input back to bottom
    const inputArea = this.el("#post-input-area");
    this.el("#main-content").appendChild(inputArea);
  }

  // ─── Submit Post ──────────────────────────────────────────────────────────

  private async handleSubmitPost(): Promise<void> {
    const textarea = this.el<HTMLTextAreaElement>('[data-cy="post-input"]');
    const msg = textarea.value;
    if (!msg.trim()) return;
    if (!this.currentWorkspace || !this.currentChannel) return;

    const parent = this.replyParentPath;

    try {
      const uriRes = await api.createPost(
        this.token,
        this.currentWorkspace,
        this.currentChannel,
        msg,
        parent,
      );
      textarea.value = "";

      // Optimistic local update: add post immediately without waiting for SSE
      const postData: PostData = {
        path: uriRes.uri,
        msg,
        parent: parent || "",
        author: this.username,
        createdAt: Date.now(),
        reactions: {},
      };
      this.posts.set(uriRes.uri, postData);
      this.renderPosts();

      // If was replying, cancel reply mode
      if (parent) {
        this.cancelReply();
      }
    } catch (err) {
      slog.warn("Failed to create post", ["error", String(err)]);
    }
  }

  // ─── Text Formatting Helpers ──────────────────────────────────────────────

  private insertFormat(before: string, after: string): void {
    const textarea = this.el<HTMLTextAreaElement>('[data-cy="post-input"]');
    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const text = textarea.value;
    const selected = text.substring(start, end);
    textarea.value =
      text.substring(0, start) + before + selected + after + text.substring(end);
    textarea.focus();
    textarea.selectionStart = start + before.length;
    textarea.selectionEnd = start + before.length + selected.length;
  }

  private insertText(text: string): void {
    const textarea = this.el<HTMLTextAreaElement>('[data-cy="post-input"]');
    const start = textarea.selectionStart;
    const val = textarea.value;
    textarea.value = val.substring(0, start) + text + val.substring(start);
    textarea.focus();
    textarea.selectionStart = textarea.selectionEnd = start + text.length;
  }

  // ─── Path Helpers ─────────────────────────────────────────────────────────

  private pathInDb(fullPath: string): string {
    const dbPath = process.env.DATABASE_PATH;
    if (fullPath.startsWith(dbPath)) {
      return fullPath.substring(dbPath.length);
    }
    return fullPath;
  }

  private nameFromPath(path: string): string {
    const clean = path.replace(/\/$/, "");
    const segments = clean.split("/").filter((s) => s.length > 0);
    return decodeURIComponent(segments[segments.length - 1]);
  }

  private escapeHtml(text: string): string {
    const div = document.createElement("div");
    div.textContent = text;
    return div.innerHTML;
  }
}

/**
 * Renders limited markdown into HTML.
 *
 * Supports:
 * - **bold** → <strong>
 * - *italic* → <em>
 * - [text](url) → <a href="url">text</a>
 * - :reaction: → iconify icon
 * - \n → <br>
 */

const REACTION_ICONS: Record<string, string> = {
  ":smile:": "mdi:emoticon-happy-outline",
  ":frown:": "mdi:emoticon-sad-outline",
  ":like:": "mdi:thumb-up-outline",
  ":celebrate:": "mdi:party-popper",
};

export function renderMarkdown(text: string): string {
  let html = escapeHtml(text);

  // Links: [text](url)
  html = html.replace(
    /\[([^\]]+)\]\(([^)]+)\)/g,
    '<a href="$2" target="_blank" rel="noopener">$1</a>',
  );

  // Bold: **text**
  html = html.replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>");

  // Italic: *text*
  html = html.replace(/\*(.+?)\*/g, "<em>$1</em>");

  // Reaction emojis: :name:
  html = html.replace(/:([a-zA-Z-]+):/g, (_match, name) => {
    const key = `:${name}:`;
    const icon = REACTION_ICONS[key];
    if (icon) {
      return `<iconify-icon icon="${icon}" aria-label="${name}" width="20" height="20"></iconify-icon>`;
    }
    return key;
  });

  // Newlines
  html = html.replace(/\n/g, "<br>");

  return html;
}

function escapeHtml(text: string): string {
  const div = document.createElement("div");
  div.textContent = text;
  return div.innerHTML;
}

declare const process: {
  env: {
    DATABASE_HOST: string;
    DATABASE_PATH: string;
    AUTH_PATH: string;
  };
};

import type { JSONSchema } from "json-schema-to-ts";
import type { FromSchema } from "json-schema-to-ts";
import { $Compiler, wrapCompilerAsTypeGuard } from "json-schema-to-ts";
import Ajv from "ajv";

// Create AJV instance for validation
const ajv = new Ajv();

// Create type-guarded compile function
const $compile: $Compiler = (schema) => ajv.compile(schema);
const compile = wrapCompilerAsTypeGuard($compile);

// ─── Auth Response ───────────────────────────────────────────────────────────

export const AuthResponseSchema = {
  $id: "auth-response.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "AuthResponse",
  type: "object",
  required: ["token"],
  properties: {
    token: { type: "string" },
  },
  additionalProperties: false,
} as const satisfies JSONSchema;

export type AuthResponse = FromSchema<typeof AuthResponseSchema>;
export const isAuthResponse = compile(AuthResponseSchema);

// ─── Document Response (single document from GET) ────────────────────────────

export const DocumentResponseSchema = {
  $id: "document-response.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "DocumentResponse",
  type: "object",
  required: ["path", "doc", "meta"],
  properties: {
    path: { type: "string" },
    doc: { type: "object" },
    meta: {
      type: "object",
      required: ["createdAt", "createdBy", "lastModifiedAt", "lastModifiedBy"],
      properties: {
        createdAt: { type: "number" },
        createdBy: { type: "string" },
        lastModifiedAt: { type: "number" },
        lastModifiedBy: { type: "string" },
      },
    },
  },
} as const satisfies JSONSchema;

export type DocumentResponse = FromSchema<typeof DocumentResponseSchema>;
export const isDocumentResponse = compile(DocumentResponseSchema);

// ─── Document Array (collection response from GET) ───────────────────────────

export const DocumentArraySchema = {
  $id: "document-array.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "DocumentArray",
  type: "array",
  items: {
    $ref: "document-response.json",
  },
} as const satisfies JSONSchema;

export type DocumentArray = FromSchema<
  typeof DocumentArraySchema,
  { references: [typeof DocumentResponseSchema] }
>;
export const isDocumentArray = compile(DocumentArraySchema);

// ─── Post Document Body ─────────────────────────────────────────────────────

export const PostDocSchema = {
  $id: "post-doc.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "PostDoc",
  type: "object",
  required: ["msg"],
  properties: {
    msg: { type: "string" },
    parent: { type: "string" },
    reactions: {
      type: "object",
      additionalProperties: {
        type: "array",
        items: { type: "string" },
      },
    },
    extensions: {
      type: "object",
      additionalProperties: true,
    },
  },
} as const satisfies JSONSchema;

export type PostDoc = FromSchema<typeof PostDocSchema>;
export const isPostDoc = compile(PostDocSchema);

// ─── URI Response (from PUT/POST) ───────────────────────────────────────────

export const UriResponseSchema = {
  $id: "uri-response.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "UriResponse",
  type: "object",
  required: ["uri"],
  properties: {
    uri: { type: "string" },
  },
} as const satisfies JSONSchema;

export type UriResponse = FromSchema<typeof UriResponseSchema>;
export const isUriResponse = compile(UriResponseSchema);

// ─── Patch Response ─────────────────────────────────────────────────────────

export const PatchResponseSchema = {
  $id: "patch-response.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "PatchResponse",
  type: "object",
  required: ["uri", "patchFailed", "message"],
  properties: {
    uri: { type: "string" },
    patchFailed: { type: "boolean" },
    message: { type: "string" },
  },
} as const satisfies JSONSchema;

export type PatchResponse = FromSchema<typeof PatchResponseSchema>;
export const isPatchResponse = compile(PatchResponseSchema);

import { fetchEventSource } from "@microsoft/fetch-event-source";
import {
  isAuthResponse,
  isDocumentArray,
  isDocumentResponse,
  isPostDoc,
  isUriResponse,
} from "./schemas";
import type { AuthResponse, DocumentArray, DocumentResponse, UriResponse } from "./schemas";
import { slog } from "./slog";

// ─── URL Helpers ─────────────────────────────────────────────────────────────

function dbUrl(): string {
  return `${process.env.DATABASE_HOST}${process.env.DATABASE_PATH}`;
}

function authUrl(): string {
  return `${process.env.DATABASE_HOST}${process.env.AUTH_PATH}`;
}

function headers(token: string, json: boolean = false): Record<string, string> {
  const h: Record<string, string> = { Authorization: `Bearer ${token}` };
  if (json) h["Content-Type"] = "application/json";
  return h;
}

// ─── Auth ────────────────────────────────────────────────────────────────────

export async function login(username: string): Promise<AuthResponse> {
  const res = await fetch(authUrl(), {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ username }),
  });
  if (!res.ok) throw new Error(`Login failed: ${res.status} ${res.statusText}`);
  const data: unknown = await res.json();
  if (!isAuthResponse(data)) throw new Error("Invalid auth response");
  return data;
}

export async function logout(token: string): Promise<void> {
  await fetch(authUrl(), {
    method: "DELETE",
    headers: { Authorization: `Bearer ${token}` },
  });
}

// ─── Workspaces ──────────────────────────────────────────────────────────────

export async function getWorkspaces(token: string): Promise<DocumentArray> {
  const res = await fetch(dbUrl(), { headers: headers(token) });
  if (!res.ok) throw new Error(`Failed to get workspaces: ${res.status}`);
  const data: unknown = await res.json();
  if (!isDocumentArray(data)) throw new Error("Invalid workspace list");
  return data;
}

export async function getWorkspace(
  token: string,
  name: string,
): Promise<DocumentResponse> {
  const res = await fetch(`${dbUrl()}${encodeURIComponent(name)}`, {
    headers: headers(token),
  });
  if (!res.ok) {
    if (res.status === 404) throw new Error(`Error: Workspace "${name}" does not exist`);
    throw new Error(`Error: Failed to open workspace (${res.status})`);
  }
  const data: unknown = await res.json();
  if (!isDocumentResponse(data)) throw new Error("Error: Invalid workspace data");
  return data;
}

export async function createWorkspace(
  token: string,
  name: string,
): Promise<void> {
  const res = await fetch(`${dbUrl()}${encodeURIComponent(name)}`, {
    method: "PUT",
    headers: headers(token, true),
    body: JSON.stringify({}),
  });
  if (!res.ok) {
    if (res.status === 409) throw new Error(`Error: Workspace "${name}" already exists`);
    throw new Error(`Error: Failed to create workspace (${res.status})`);
  }
  // Create channels collection
  await fetch(`${dbUrl()}${encodeURIComponent(name)}/channels/`, {
    method: "PUT",
    headers: headers(token),
  });
}

export async function deleteWorkspace(
  token: string,
  name: string,
): Promise<void> {
  const res = await fetch(`${dbUrl()}${encodeURIComponent(name)}`, {
    method: "DELETE",
    headers: headers(token),
  });
  if (!res.ok) {
    if (res.status === 404) throw new Error(`Error: Workspace "${name}" does not exist`);
    throw new Error(`Error: Failed to delete workspace (${res.status})`);
  }
}

