// ─── Posts ────────────────────────────────────────────────────────────────────

export async function getPosts(
  token: string,
  workspace: string,
  channel: string,
): Promise<DocumentArray> {
  const res = await fetch(
    `${dbUrl()}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}/posts/`,
    { headers: headers(token) },
  );
  if (!res.ok) throw new Error(`Failed to get posts: ${res.status}`);
  const data: unknown = await res.json();
  if (!isDocumentArray(data)) throw new Error("Invalid post list");
  return data;
}

export async function createPost(
  token: string,
  workspace: string,
  channel: string,
  msg: string,
  parent: string = "",
): Promise<UriResponse> {
  const body: Record<string, string> = { msg };
  if (parent) body.parent = parent;
  else body.parent = "";
  const res = await fetch(
    `${dbUrl()}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}/posts/`,
    { method: "POST", headers: headers(token, true), body: JSON.stringify(body) },
  );
  if (!res.ok) throw new Error(`Failed to create post: ${res.status}`);
  const data: unknown = await res.json();
  if (!isUriResponse(data)) throw new Error("Invalid post creation response");
  return data;
}

export async function patchReactions(
  token: string,
  postFullPath: string,
  reactions: Record<string, string[]>,
): Promise<void> {
  const url = `${process.env.DATABASE_HOST}${postFullPath}`;
  const res = await fetch(url, {
    method: "PATCH",
    headers: headers(token, true),
    body: JSON.stringify([
      { op: "ObjectAdd", path: "/reactions", value: reactions },
    ]),
  });
  if (!res.ok) throw new Error(`Failed to update reactions: ${res.status}`);
}

// ─── SSE Subscription ───────────────────────────────────────────────────────

export interface PostEvent {
  type: "update" | "delete";
  path: string;
  doc?: Record<string, unknown>;
  meta?: {
    createdAt: number;
    createdBy: string;
    lastModifiedAt: number;
    lastModifiedBy: string;
  };
}

export function subscribeToChannel(
  token: string,
  workspace: string,
  channel: string,
  onEvent: (event: PostEvent) => void,
  signal: AbortSignal,
): void {
  const url = `${dbUrl()}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}/posts/?mode=subscribe`;

  fetchEventSource(url, {
    method: "GET",
    headers: { Authorization: `Bearer ${token}`, Accept: "text/event-stream" },
    signal,
    onmessage(ev) {
      if (ev.event === "update") {
        try {
          const data: unknown = JSON.parse(ev.data);
          if (isDocumentResponse(data)) {
            const doc = data.doc as Record<string, unknown>;
            if (isPostDoc(doc)) {
              onEvent({
                type: "update",
                path: data.path,
                doc,
                meta: data.meta as PostEvent["meta"],
              });
            }
          }
        } catch (e) {
          slog.warn("Failed to parse SSE update", ["error", String(e)]);
        }
      } else if (ev.event === "delete") {
        try {
          const path = JSON.parse(ev.data);
          if (typeof path === "string") {
            onEvent({ type: "delete", path });
          }
        } catch (e) {
          slog.warn("Failed to parse SSE delete", ["error", String(e)]);
        }
      }
    },
    onerror(err) {
      slog.warn("SSE connection error", ["error", String(err)]);
    },
    openWhenHidden: true,
  });
}

