+  isPostDoc,
+  isUriResponse,
+} from "./schemas";
+import type { AuthResponse, DocumentArray, DocumentResponse, UriResponse } from "./schemas";
+import { slog } from "./slog";
+
+// ─── URL Helpers ─────────────────────────────────────────────────────────────
+
+function dbUrl(): string {
+  return `${process.env.DATABASE_HOST}${process.env.DATABASE_PATH}`;
+}
+
+function authUrl(): string {
+  return `${process.env.DATABASE_HOST}${process.env.AUTH_PATH}`;
+}
+
+function headers(token: string, json: boolean = false): Record<string, string> {
+  const h: Record<string, string> = { Authorization: `Bearer ${token}` };
+  if (json) h["Content-Type"] = "application/json";
+  return h;
+}
+
+// ─── Auth ────────────────────────────────────────────────────────────────────
+
+export async function login(username: string): Promise<AuthResponse> {
+  const res = await fetch(authUrl(), {
+    method: "POST",
+    headers: { "Content-Type": "application/json" },
+    body: JSON.stringify({ username }),
+  });
+  if (!res.ok) throw new Error(`Login failed: ${res.status} ${res.statusText}`);
+  const data: unknown = await res.json();
+  if (!isAuthResponse(data)) throw new Error("Invalid auth response");
+  return data;
+}
+
+export async function logout(token: string): Promise<void> {
+  await fetch(authUrl(), {
+    method: "DELETE",
+    headers: { Authorization: `Bearer ${token}` },
+  });
+}
+
