+    if (!this.currentWorkspace) return;
+    this.hideError();
+    try {
+      await api.deleteChannel(this.token, this.currentWorkspace, name);
+      if (this.currentChannel === name) {
+        this.closeChannel();
+      }
+      await this.loadChannels();
+    } catch (err) {
+      this.showError(err instanceof Error ? err.message : "Error deleting channel");
+    }
+  }
+
+  private closeChannel(): void {
+    this.abortController?.abort();
+    this.abortController = null;
+    this.currentChannel = "";
+    this.posts.clear();
+    this.replyParentPath = "";
+    this.el("#channel-header").style.display = "none";
+    this.el("#channel-name").textContent = "";
+    this.el("#post-container").innerHTML = "";
+    this.el("#post-input-area").style.display = "none";
+    this.el("#reply-indicator").style.display = "none";
+    // Move input back to bottom
+    const inputArea = this.el("#post-input-area");
+    this.el("#main-content").appendChild(inputArea);
+  }
+
+  // ─── Posts ────────────────────────────────────────────────────────────────
+
+  private async subscribeToPosts(): Promise<void> {
+    if (!this.currentWorkspace || !this.currentChannel) return;
+
+    this.abortController?.abort();
+    this.abortController = new AbortController();
+    this.posts.clear();
+    this.el("#post-container").innerHTML = "";
+
+    // First GET existing posts
+    try {
+      const docs = await api.getPosts(
+        this.token,
+        this.currentWorkspace,
+        this.currentChannel,
+      );
+      for (const doc of docs) {
+        this.processPostEvent({
+          type: "update",
+          path: doc.path,
+          doc: doc.doc as Record<string, unknown>,
+          meta: doc.meta as PostEvent["meta"],
+        });
+      }
+    } catch (err) {
+      slog.warn("Failed to load posts", ["error", String(err)]);
+    }
+
+    // Then subscribe for live updates
+    api.subscribeToChannel(
+      this.token,
+      this.currentWorkspace,
+      this.currentChannel,
+      (event) => this.processPostEvent(event),
+      this.abortController.signal,
+    );
+  }
+
+  private processPostEvent(event: PostEvent): void {
+    if (event.type === "update" && event.doc && event.meta) {
+      if (!isPostDoc(event.doc)) return;
+      const postData: PostData = {
+        path: event.path,
+        msg: String(event.doc.msg || ""),
+        parent: String(event.doc.parent || ""),
+        author: event.meta.createdBy,
+        createdAt: event.meta.createdAt,
+        reactions: (event.doc.reactions || {}) as Record<string, string[]>,
+      };
+      this.posts.set(event.path, postData);
+      this.renderPosts();
+    } else if (event.type === "delete") {
+      this.posts.delete(event.path);
+      this.renderPosts();
+    }
+  }
+
+  private renderPosts(): void {
+    const container = this.el("#post-container");
+    const flatList = this.buildFlatPostList();
+
+    // Remember where the input area is
+    const inputArea = this.el("#post-input-area");
+    const inputParentPath = this.replyParentPath;
+
+    container.innerHTML = "";
+
+    for (const { post, depth } of flatList) {
+      const postEl = this.createPostElement(post, depth);
+      container.appendChild(postEl);
+
+      // If we're replying to this post, insert input after it
+      if (inputParentPath && this.pathInDb(post.path) === inputParentPath) {
+        container.appendChild(inputArea);
+      }
+    }
+
+    // If not replying (or reply parent not found), input stays at bottom
+    if (!inputParentPath) {
+      this.el("#main-content").appendChild(inputArea);
+    }
+  }
+
+  private buildFlatPostList(): FlatPost[] {
+    const allPosts = Array.from(this.posts.values());
+    // Build parent -> children map
+    const childMap = new Map<string, PostData[]>();
+    const topLevel: PostData[] = [];
+
+    for (const p of allPosts) {
+      const parentKey = p.parent || "";
+      if (!parentKey) {
+        topLevel.push(p);
+      } else {
+        // Find parent by matching pathInDb
+        let matched = false;
+        for (const candidate of allPosts) {
+          if (this.pathInDb(candidate.path) === parentKey) {
+            const children = childMap.get(candidate.path) || [];
+            children.push(p);
+            childMap.set(candidate.path, children);
+            matched = true;
+            break;
+          }
+        }
+        if (!matched) {
+          // Parent not found, treat as top-level
+          topLevel.push(p);
+        }
+      }
+    }
+
+    // Sort by creation time
+    topLevel.sort((a, b) => a.createdAt - b.createdAt);
+
+    // DFS to flatten
+    const result: FlatPost[] = [];
+    const dfs = (posts: PostData[], depth: number) => {
+      for (const p of posts) {
+        result.push({ post: p, depth });
+        const children = childMap.get(p.path) || [];
+        children.sort((a, b) => a.createdAt - b.createdAt);
+        dfs(children, depth + 1);
+      }
+    };
+    dfs(topLevel, 0);
+    return result;
+  }
+
+  private createPostElement(post: PostData, depth: number): HTMLElement {
+    const el = document.createElement("div");
+    el.className = "post-item";
+    el.setAttribute("data-cy", "post-item");
+    el.setAttribute("data-post-path", post.path);
+    el.style.marginLeft = `${depth * 30}px`;
+
+    const time = new Date(post.createdAt).toLocaleString();
+
+    // Build reactions HTML
+    let reactionsHtml = "";
+    for (const r of REACTIONS) {
+      const users = post.reactions[r.name] || [];
+      const count = users.length;
+      const active = users.includes(this.username) ? " active" : "";
+      reactionsHtml += `
+        <button class="reaction-btn${active}" data-reaction="${r.name}"
+                aria-label="${r.label} reaction" title="${r.name}">
+          <iconify-icon icon="${r.icon}" aria-label="${r.label}" width="16" height="16"></iconify-icon>
+          <span class="reaction-count">${count > 0 ? count : ""}</span>
+        </button>
+      `;
+    }
+
+    el.innerHTML = `
+      <div class="post-header">
+        <strong class="post-author">${this.escapeHtml(post.author)}</strong>
+        <span class="post-time">${this.escapeHtml(time)}</span>
+      </div>
+      <div class="post-body">${renderMarkdown(post.msg)}</div>
+      <div class="post-actions">
+        <div class="reactions">${reactionsHtml}</div>
+        <button class="reply-btn" data-cy="reply-btn" aria-label="Reply">Reply</button>
+      </div>
+    `;
+
+    // Reaction click handlers
+    el.querySelectorAll(".reaction-btn").forEach((btn) => {
+      btn.addEventListener("click", (e) => {
+        e.stopPropagation();
+        const reaction = (btn as HTMLElement).getAttribute("data-reaction") || "";
+        this.handleReaction(post, reaction);
+      });
+    });
+
+    // Reply click handler
+    el.querySelector(".reply-btn")?.addEventListener("click", () => {
+      this.startReply(post);
+    });
+
+    return el;
+  }
+
+  // ─── Reactions ────────────────────────────────────────────────────────────
+
+  private async handleReaction(post: PostData, reactionName: string): Promise<void> {
+    const currentUsers = post.reactions[reactionName] || [];
+    let newUsers: string[];
+    if (currentUsers.includes(this.username)) {
+      newUsers = currentUsers.filter((u) => u !== this.username);
+    } else {
+      newUsers = [...currentUsers, this.username];
+    }
+
+    const newReactions = { ...post.reactions, [reactionName]: newUsers };
+
+    try {
+      await api.patchReactions(this.token, post.path, newReactions);
+      // Optimistically update local state
+      post.reactions = newReactions;
+      this.renderPosts();
+    } catch (err) {
+      slog.warn("Failed to update reaction", ["error", String(err)]);
+    }
+  }
+
+  // ─── Reply ────────────────────────────────────────────────────────────────
+
+  private startReply(post: PostData): void {
+    this.replyParentPath = this.pathInDb(post.path);
+    this.el("#reply-indicator").style.display = "flex";
+    this.renderPosts();
+    this.el<HTMLTextAreaElement>('[data-cy="post-input"]').focus();
+  }
+
+  private cancelReply(): void {
+    this.replyParentPath = "";
+    this.el("#reply-indicator").style.display = "none";
